```c
void filter_objects_from_level()
{
	int i;

	mprintf((0, "Highest object index=%d\n", Highest_object_index));

	for (i = 0; i <= Highest_object_index; i++)
	{
		if (Objects[i].type == OBJ_POWERUP)
			if (Objects[i].id == POW_FLAG_RED || Objects[i].id == POW_FLAG_BLUE)
				bash_to_shield(i, "Flag!!!!");
	}
}
```

**Purpose:** Iterates through all objects in the level and converts any red or blue flag powerups into shield boost powerups.

---

### `bash_to_shield()` (lines 2266-2300)

**Full function body:**
```c
void bash_to_shield(int i, const char* s)
{
#ifdef USE_OX_BRIDGE
	if (cd_ox_is_ready()) {
		/* Register gameseq effects on first call */
		static int gs_reg = 0;
		if (!gs_reg) {
			gs_reg = 1;
			cd_ox_register_gameseq_effects(
				[](int objnum, int32_t* out) {
					out[0] = Objects[objnum].id;
					int shield_vclip = Powerup_info[POW_SHIELD_BOOST].vclip_num;
					out[1] = shield_vclip;
					out[2] = Vclip[shield_vclip].frame_time;
				},
				[](const int32_t* packed, int len) {
					if (len < 5) return;
					int objnum = packed[0];
					Objects[objnum].id = packed[2];
					Objects[objnum].rtype.vclip_info.vclip_num = packed[3];
					Objects[objnum].rtype.vclip_info.frametime = packed[4];
				});
		}
		cd_ox_bash_to_shield(i);
		return;
	}
#endif
	int type = Objects[i].id;

	mprintf((0, "Bashing %s object #%i to shield.\n", s, i));

	Objects[i].id = POW_SHIELD_BOOST;
	Objects[i].rtype.vclip_info.vclip_num = Powerup_info[Objects[i].id].vclip_num;
	Objects[i].rtype.vclip_info.frametime = Vclip[Objects[i].rtype.vclip_info.vclip_num].frame_time;
}
```

**Purpose:** Converts a powerup object (at index `i`) into a shield boost powerup by updating its `id`, `vclip_num`, and `frametime`. When OCaml bridge is available, delegates to `cd_ox_bash_to_shield()`.

